import React from 'react';
import '../styles/Events.css';

const Events = () => {
  return (
    <div className="events-container">
      <h1>Upcoming Events</h1>
      <div className="events-content">
        <p>Join us for conservation events and workshops.</p>
      </div>
    </div>
  );
};

export default Events;
